-- Create overnight batch tickets for all agents
-- Each agent gets specific, actionable tickets for 24/7 operation

INSERT INTO agent_tickets (id, title, description, status, priority, category, agent_id, agent_name, is_agent_ticket, source, metadata) VALUES

-- Backend Dev (Opus) - urgent + high
('tkt_overnight_be01', 'Fix metabolic/lessons endpoint database schema error', 'The /api/v1/metabolic/lessons endpoint is crashing with a database schema error. This is a CRITICAL production issue. Steps: 1) Read the endpoint handler in apps/api/src/index.ts, search for metabolic/lessons. 2) Check the database schema for the relevant tables. 3) Identify the schema mismatch. 4) Fix the query or add the missing column/table. 5) Test the endpoint. Use substrate_db_query to inspect the schema. Use file_ops to read and fix the code. This ticket is also referenced as 00MLHG1KNJ2C57588EF6784CAF.', 'open', 'urgent', 'bug-fix', '01KGXGV6RSSKVXEF8X2S79R3KR', 'Backend Dev', true, 'human', '{"overnight_batch": true}'),

('tkt_overnight_be02', 'Audit API error handling across all endpoints', 'Review all API endpoints in apps/api/src/index.ts for proper error handling. Check for: 1) Endpoints that throw unhandled errors (no try/catch). 2) Endpoints returning raw error objects. 3) Missing status codes. 4) SQL injection vectors. Read the main API file, audit each endpoint, create findings for any issues via finding_ops. Do NOT modify code, audit and report only.', 'open', 'high', 'audit', '01KGXGV6RSSKVXEF8X2S79R3KR', 'Backend Dev', true, 'human', '{"overnight_batch": true}'),

-- Frontend Dev (Opus)
('tkt_overnight_fe01', 'Dashboard performance audit and optimization recommendations', 'Audit dashboard app (apps/dashboard/) for performance issues. 1) Review page components for unnecessary re-renders. 2) Check for missing React.memo/useMemo/useCallback. 3) Identify components fetching data on every render. 4) Look for large imports that could be lazy-loaded. 5) Check CSS animations for layout thrashing. Review: OrchestrationHub.tsx, ContentShards.tsx, Analytics.tsx. Create findings for each issue.', 'open', 'medium', 'performance', '01KGXGV6R7KD6F3WD0MGASRHYY', 'Frontend Dev', true, 'human', '{"overnight_batch": true}'),

('tkt_overnight_fe02', 'Implement error boundary components for dashboard resilience', 'The dashboard needs error boundaries to prevent white-screen crashes. 1) Read existing dashboard structure (apps/dashboard/src/App.tsx). 2) Create an ErrorBoundary component that catches React render errors. 3) Wrap major page sections with error boundaries. 4) Show user-friendly error state with retry button. 5) Log errors to console. Work on branch agent/frontend-dev/error-boundaries.', 'open', 'medium', 'feature', '01KGXGV6R7KD6F3WD0MGASRHYY', 'Frontend Dev', true, 'human', '{"overnight_batch": true}'),

-- Architect (Opus)
('tkt_overnight_arch01', 'Design proposal: Agent execution retry and circuit breaker pattern', 'Design resilience patterns for agent fleet. Cover: 1) Retry policy (retryable vs permanent failures). 2) Exponential backoff with jitter. 3) Circuit breaker (pause schedule after N failures). 4) Dead letter queue for human review. 5) Integration with worker.ts and container-result-listener.ts. Review the execution flow files and write design as finding with category architecture. Do NOT implement, design and document only.', 'open', 'high', 'architecture', '01KGXGV6QBPG0S0VGRY64T7D1W', 'Architect', true, 'human', '{"overnight_batch": true}'),

('tkt_overnight_arch02', 'Review database indexing strategy and propose optimizations', 'Audit all database tables in substrate and forge databases. 1) Check pg_stat_user_tables for high sequential scan counts. 2) Check pg_stat_user_indexes for unused indexes. 3) Verify all FKs have indexes. 4) Look for composite index opportunities. 5) Check index bloat. Use substrate_db_query for diagnostics. Create findings for each optimization.', 'open', 'medium', 'performance', '01KGXGV6QBPG0S0VGRY64T7D1W', 'Architect', true, 'human', '{"overnight_batch": true}'),

-- QA Engineer (Opus)
('tkt_overnight_qa01', 'Comprehensive Forge API endpoint validation', 'Test every Forge API endpoint. Test: GET/POST /api/v1/forge/agents, GET/PUT agents/:id, POST/GET executions, fleet memory endpoints, coordination endpoints. For each: valid request, missing fields (400), invalid ID (404), pagination. Use api_call with base URL http://forge:3005. Report findings for any failures.', 'open', 'high', 'testing', '01KGXGV6S74J5BKEZHDJ8Q672K', 'QA Engineer', true, 'human', '{"overnight_batch": true}'),

('tkt_overnight_qa02', 'Validate agent container health and MCP tool connectivity', 'Check all 18 agent containers are healthy and MCP tools accessible. 1) Query Redis for agent heartbeats (agent:*:heartbeat). 2) Query agent statuses (agent:*:status). 3) Verify heartbeats are recent (<2 min). 4) Check for stuck processing state. 5) Test MCP connectivity on all 4 servers (workflow:3010, data:3011, infra:3012, alf:3013). Report findings.', 'open', 'high', 'testing', '01KGXGV6S74J5BKEZHDJ8Q672K', 'QA Engineer', true, 'human', '{"overnight_batch": true}'),

-- DevOps (Haiku)
('tkt_overnight_devops01', 'Docker security audit for all containers', 'Security audit of Docker infrastructure. 1) List all containers and image versions. 2) Check for root containers. 3) Verify cap_drop: ALL. 4) Check for privileged mode. 5) Verify read_only filesystem. 6) Check exposed ports. 7) Review volume mount permissions. Use docker_api and security_scan. Create findings with severity ratings.', 'open', 'high', 'security', '01KGXGV6SKXJKJMF3K4HQSQ8VB', 'DevOps', true, 'human', '{"overnight_batch": true}'),

('tkt_overnight_devops02', 'Monitor and report container resource usage overnight', 'Track resource utilization for capacity planning. 1) Docker stats for all containers (CPU%, memory, I/O). 2) Containers using >70% memory limit. 3) Disk usage on volumes. 4) Redis memory usage. 5) PostgreSQL connection count. 6) Total fleet resource footprint. Use docker_api and db_query. Create comprehensive finding.', 'open', 'medium', 'monitoring', '01KGXGV6SKXJKJMF3K4HQSQ8VB', 'DevOps', true, 'human', '{"overnight_batch": true}'),

-- API Tester (Haiku)
('tkt_overnight_api01', 'Full regression test of public API endpoints', 'Test all public-facing endpoints. Health endpoints, chat endpoints, shard endpoints, auth validation, analytics endpoints. For each: test happy path, error paths, measure response time, verify response format. Use api_call with base URL http://api:3000. Report findings for failures or slow responses (>1s).', 'open', 'medium', 'testing', '01KGXGV6T1N9RJMHF44MFX6WA3', 'API Tester', true, 'human', '{"overnight_batch": true}'),

-- Data Engineer (Sonnet)
('tkt_overnight_data01', 'Database query performance audit', 'Audit PostgreSQL for slow queries. 1) Check pg_stat_statements if enabled. 2) EXPLAIN ANALYZE key queries (tickets, executions, shards, agents). 3) Check table bloat (n_dead_tup vs n_live_tup). 4) Tables needing VACUUM/ANALYZE. 5) Connection pool stats. Use substrate_db_query for both databases. Create findings with recommendations.', 'open', 'medium', 'performance', '01KGXGV6TD7REMT407ZV7QTSB6', 'Data Engineer', true, 'human', '{"overnight_batch": true}'),

('tkt_overnight_data02', 'Audit data integrity across all agent-related tables', 'Check data integrity. 1) Orphaned execution records. 2) Tickets assigned to non-existent agents. 3) Schedules for deleted agents. 4) Duplicate names/IDs. 5) Executions stuck in pending/running >1 hour. 6) FK consistency. 7) NULL values in required fields. Query both databases. Create findings for any issues.', 'open', 'medium', 'audit', '01KGXGV6TD7REMT407ZV7QTSB6', 'Data Engineer', true, 'human', '{"overnight_batch": true}'),

-- Doc Writer (Sonnet)
('tkt_overnight_doc01', 'Generate comprehensive Forge API documentation', 'Create documentation for all Forge API endpoints. Read apps/forge/src/routes/ and document every route: HTTP method, path, params, request body, response format, auth requirements, error responses. Document the execution lifecycle and MCP tool system. Write as finding with category documentation.', 'open', 'medium', 'documentation', '01KGXGV6TY5VJ7GAK9JW1T79SZ', 'Doc Writer', true, 'human', '{"overnight_batch": true}'),

('tkt_overnight_doc02', 'Document agent container architecture and deployment guide', 'Create operational docs for agent container fleet. Cover: architecture overview, adding new agents, updating configs, debugging guide (logs, heartbeats, stuck tasks), schedule management, OAuth credential setup and rotation, common failures and troubleshooting. Read agent-daemon.ts, docker-compose.agents.yml, generate-agent-config.js. Write as finding.', 'open', 'medium', 'documentation', '01KGXGV6TY5VJ7GAK9JW1T79SZ', 'Doc Writer', true, 'human', '{"overnight_batch": true}'),

-- Forge Smith (Opus)
('tkt_overnight_fs01', 'Audit and optimize agent tool configurations across the fleet', 'Review all agent MCP configs and tool access. 1) Read all agent-configs/*/mcp.json files. 2) Check for missing tools per role. 3) Check for excessive tool access. 4) Verify all 4 MCP servers in configs. 5) Check URLs and transport type. 6) Review CLAUDE.md accuracy. Create findings for misconfigurations with specific fixes.', 'open', 'high', 'audit', '01KGXG4SS55GBA5SRZBVV8E1NR', 'Forge Smith', true, 'human', '{"overnight_batch": true}'),

-- Herald (Sonnet)
('tkt_overnight_herald01', 'Generate comprehensive fleet activity report for last 24 hours', 'Create detailed status report. Include: 1) Total executions (completed vs failed by agent). 2) Ticket throughput (opened vs resolved by priority). 3) Agent availability (uptime via heartbeats). 4) Cost summary by agent and model tier. 5) Notable findings (critical/high severity). 6) Knowledge crystallization (new shards/packs). Query forge_executions, agent_tickets, agent_findings. Create finding with category report.', 'open', 'medium', 'report', '01KGXG4SV2ZQH936ZQVJ81JP9M', 'Herald', true, 'human', '{"overnight_batch": true}'),

-- Quartermaster (Haiku)
('tkt_overnight_qm01', 'Audit fleet cost efficiency and resource allocation', 'Analyze cost-effectiveness. 1) Cost per agent over last 7 days. 2) Cost per successful vs failed execution. 3) Most expensive agents. 4) Model tier appropriateness. 5) Budget limits vs actual spending. 6) Recommend budget adjustments. Use db_query against forge database. Create finding with category cost-analysis.', 'open', 'medium', 'cost-analysis', '01KGXG4STMCPSY1F60ZX5TBZFX', 'Quartermaster', true, 'human', '{"overnight_batch": true}'),

-- Concierge (Haiku)
('tkt_overnight_con01', 'Audit ALF chat experience and identify improvements', 'Test ALF chat system. 1) Check recent chat session error rates. 2) Query chat_messages for tool_use sessions. 3) Check shard fast-path hit rate. 4) Review ALF profile data quality. 5) Find common user questions ALF struggles with. 6) Identify knowledge base gaps. Use substrate_db_query. Create findings for issues.', 'open', 'medium', 'user-experience', '01KGXG4ST1DR9KPM6S4EB56A6G', 'Concierge', true, 'human', '{"overnight_batch": true}'),

-- Shard Curator (Sonnet)
('tkt_overnight_sc01', 'Mine fleet memory for new knowledge shards — overnight crystallization', 'Run comprehensive knowledge crystallization. 1) Query fleet episodic memory for quality >= 0.8 from last 48h. 2) Identify recurring patterns across agent experiences. 3) Group related episodes into themes. 4) For themes with 3+ episodes, create candidate shards. 5) Check orphaned promoted shards, organize into packs. 6) Propose new packs via intervention if needed. Use memory_search and substrate_db_query. Target: at least 3 new candidate shards.', 'open', 'high', 'knowledge', '01KH295596E1CVNTRQDHWZXKEB', 'Shard Curator', true, 'human', '{"overnight_batch": true}'),

-- Nightwatch (Haiku)
('tkt_overnight_nw01', 'Overnight security monitoring — check for anomalies and threats', 'Comprehensive security scan. 1) Verify all services running and healthy. 2) Check for failed auth attempts. 3) Review agent executions for unauthorized operations. 4) Check Redis for unexpected keys. 5) Verify Cloudflare tunnel active. 6) Check for exposed ports. 7) Review Docker logs for intrusion patterns. 8) Verify TLS certificates. Use security_scan and docker_api. Create findings.', 'open', 'high', 'security', '01KGXG4SRNPS9XT49VR1N8FSMB', 'Nightwatch', true, 'human', '{"overnight_batch": true}'),

-- Metabolist (Haiku)
('tkt_overnight_met01', 'Convergence metrics analysis and environmental impact report', 'Analyze convergence cycle and environmental data. 1) Query convergence_stats for current metrics. 2) Calculate trends over time. 3) Check shard hit rate. 4) Analyze which domains have highest convergence impact. 5) Identify areas for resource savings. 6) Generate formatted impact summary. Use substrate_db_query. Create finding with category convergence.', 'open', 'medium', 'convergence', '01KH1ZKR0001CONVERGENCEOP01', 'Metabolist', true, 'human', '{"overnight_batch": true}'),

-- Overseer (Haiku)
('tkt_overnight_ov01', 'Fleet execution success rate audit — identify underperforming agents', 'Analyze execution success rates across fleet. 1) Query forge_executions grouped by agent for last 7 days. 2) Calculate success rate per agent. 3) Identify agents < 80% success rate. 4) Analyze common error patterns. 5) Check if failures correlate with times/models/tasks. 6) Recommend fixes. Use db_query against forge DB. Create findings. If consistent failures, create intervention.', 'open', 'high', 'fleet-management', '01KGXG4SVERD6E8BHKVMK6JTBY', 'Overseer', true, 'human', '{"overnight_batch": true}'),

-- Sentinel (Haiku)
('tkt_overnight_sent01', 'Comprehensive infrastructure health check — all services and databases', 'Full health check. 1) API (api:3000/health). 2) Forge (forge:3005/health). 3) Dashboard. 4) MCP servers (3010-3013). 5) Redis (PING, memory, clients). 6) PostgreSQL (connections, DB sizes). 7) SearXNG (searxng:8080). 8) Cloudflare tunnel. For each: status, response time, errors. Use api_call, db_query, docker_api. Create finding with full health report.', 'open', 'high', 'monitoring', '01KGXG4SNRAAGWE0F4Z44NXB5S', 'Sentinel', true, 'human', '{"overnight_batch": true}'),

